#!/bin/bash
version=$(bin/neo4j-admin --version | cut -d '.' -f 1)
if [[ $version -ge 5 ]]; then
	bin/neo4j-admin database import full neo4j --delimiter=";" --array-delimiter="|" --quote="'" --overwrite-destination=true --nodes="/home/sthoniyot/projects/cardiometabolic-kg/data/processed/biocypher-out/Phenotype-header.csv,/home/sthoniyot/projects/cardiometabolic-kg/data/processed/biocypher-out/Phenotype-part.*" --nodes="/home/sthoniyot/projects/cardiometabolic-kg/data/processed/biocypher-out/Snp-header.csv,/home/sthoniyot/projects/cardiometabolic-kg/data/processed/biocypher-out/Snp-part.*" --nodes="/home/sthoniyot/projects/cardiometabolic-kg/data/processed/biocypher-out/Gene-header.csv,/home/sthoniyot/projects/cardiometabolic-kg/data/processed/biocypher-out/Gene-part.*" --relationships="/home/sthoniyot/projects/cardiometabolic-kg/data/processed/biocypher-out/SnpToGene-header.csv,/home/sthoniyot/projects/cardiometabolic-kg/data/processed/biocypher-out/SnpToGene-part.*" --relationships="/home/sthoniyot/projects/cardiometabolic-kg/data/processed/biocypher-out/SnpToPhenotype-header.csv,/home/sthoniyot/projects/cardiometabolic-kg/data/processed/biocypher-out/SnpToPhenotype-part.*" 
else
	bin/neo4j-admin import --database=neo4j --delimiter=";" --array-delimiter="|" --quote="'" --force=true --nodes="/home/sthoniyot/projects/cardiometabolic-kg/data/processed/biocypher-out/Phenotype-header.csv,/home/sthoniyot/projects/cardiometabolic-kg/data/processed/biocypher-out/Phenotype-part.*" --nodes="/home/sthoniyot/projects/cardiometabolic-kg/data/processed/biocypher-out/Snp-header.csv,/home/sthoniyot/projects/cardiometabolic-kg/data/processed/biocypher-out/Snp-part.*" --nodes="/home/sthoniyot/projects/cardiometabolic-kg/data/processed/biocypher-out/Gene-header.csv,/home/sthoniyot/projects/cardiometabolic-kg/data/processed/biocypher-out/Gene-part.*" --relationships="/home/sthoniyot/projects/cardiometabolic-kg/data/processed/biocypher-out/SnpToGene-header.csv,/home/sthoniyot/projects/cardiometabolic-kg/data/processed/biocypher-out/SnpToGene-part.*" --relationships="/home/sthoniyot/projects/cardiometabolic-kg/data/processed/biocypher-out/SnpToPhenotype-header.csv,/home/sthoniyot/projects/cardiometabolic-kg/data/processed/biocypher-out/SnpToPhenotype-part.*" 
fi